.darma-loader-darma-custom-506 {color: var(--loader-color, #dc2626);
   width: 40px;
   aspect-ratio: 1;
   position: relative;
}
.darma-loader-darma-custom-506:before, .darma-loader-darma-custom-506:after  {
  content: "";
   position: absolute;
   top: 0;
   left: 0;
   margin: -8px 0 0 -8px;
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #dc2626);
   animation: darma-loader-darma-custom-506-l2-1 2s infinite, darma-loader-darma-custom-506-l2-2 1s infinite ;
}
.darma-loader-darma-custom-506:after  {
  background:var(--loader-secondary-color, #f97316);
   animation-delay: -1s,0s;
}
@keyframes darma-loader-darma-custom-506-l2-1  {
  0% {top:0 ;
  left:0}
25% {top:100%;
  left:0}
50% {top:100%;
  left:100%}
75% {top:0 ;
  left:100%}
100% {top:0 ;
  left:0}
}
@keyframes darma-loader-darma-custom-506-l2-2  {
  40%,50% {transform: rotate(0.25turn) scale(0.5)}
100% {transform: rotate(0.5turn) scale(1)}
}

